code = """import json
import pandas as pd
import os

# Load the data
var_name = 'var_functions.query_db:14'
if var_name in locals():
    data_file = locals()[var_name]
    if isinstance(data_file, str) and data_file.endswith('.json'):
        with open(data_file, 'r') as f:
            patents_data = json.load(f)
    else:
        patents_data = data_file
else:
    patents_data = []

result_log = ['Total patents in Germany 2019: ' + str(len(patents_data))]

# Parse the data to extract grant dates and CPC codes
records = []
for patent in patents_data:
    grant_date_str = patent.get('grant_date', '')
    cpc_str = patent.get('cpc', '[]')
    try:
        cpc_codes = json.loads(cpc_str)
        if isinstance(cpc_codes, list):
            for cpc_entry in cpc_codes:
                code = cpc_entry.get('code', '')
                if code and len(code) >= 4:
                    cpc_group = code[:4]
                    records.append({
                        'grant_date': grant_date_str,
                        'full_code': code,
                        'group_code': cpc_group
                    })
    except json.JSONDecodeError:
        continue

df = pd.DataFrame(records)
result_log.append('Total CPC entries: ' + str(len(df)))

if not df.empty:
    month_map = {'Jan': 1, 'Feb': 2, 'Mar': 3, 'Apr': 4, 'May': 5, 'Jun': 6,
                 'Jul': 7, 'Aug': 8, 'Sep': 9, 'Oct': 10, 'Nov': 11, 'Dec': 12}
    
    def extract_month(date_str):
        if not date_str:
            return None
        date_lower = date_str.lower()
        for month_name, num in month_map.items():
            if month_name.lower() in date_lower:
                return num
        return None
    
    df['grant_month'] = df['grant_date'].apply(extract_month)
    second_half_df = df[df['grant_month'].isin(range(7, 13))]
    result_log.append('Patents in second half of 2019: ' + str(len(second_half_df)))
    
    if not second_half_df.empty:
        yearly_counts = second_half_df.groupby('group_code').size().reset_index(name='count')
        yearly_counts = yearly_counts.sort_values('count', ascending=False)
        
        get_top = min(50, len(yearly_counts))
        top_groups = yearly_counts.head(get_top)['group_code'].tolist()
        
        output = {'status': 'processed', 'record_count': len(second_half_df),
                  'top_groups': top_groups, 'log': result_log}
        print('__RESULT__:')
        print(json.dumps(output))
    else:
        print('__RESULT__:')
        print(json.dumps({'status': 'no_h2_data', 'log': result_log}))
else:
    print('__RESULT__:')
    print(json.dumps({'status': 'empty_data', 'log': result_log}))"""

